import { Anthropic } from '@anthropic-ai/sdk';

const client = new Anthropic();

const tools = [{
  name: 'search_documents',
  input_schema: {
    type: 'object',
    properties: { query: { type: 'string' }, top_k: { type: 'number' } }
  }
}];

async function handleToolCall(toolCall: any) {
  if (toolCall.name === 'search_documents') {
    const results = await pinecone.query({
      vector: embed(toolCall.input.query),
      topK: toolCall.input.top_k || 5
    });
    return {
      type: 'tool_result',
      tool_use_id: toolCall.id,
      content: JSON.stringify(results.matches)
    };
  }
}

